// commentRowIDs collects the row ids for the bulk-selection Alpine store.
func commentRowIDs(rows []CommentAdminRow) []string {
	ids := make([]string, 0, len(rows))
	for _, r := range rows {
		ids = append(ids, r.ID)
	}
	return ids
}

// commentBulkActions is the moderation bulk-action bar spec: approve/spam/trash
// are non-destructive; permanent delete opens the confirm modal.
func commentBulkActions() []BulkActionSpec {
	return []BulkActionSpec{
		{Action: "approve", Label: "Approve"},
		{Action: "spam", Label: "Mark spam"},
		{Action: "trash", Label: "Trash"},
		{Action: "delete", Label: "Delete", Destructive: true, Consequence: "Permanently delete the selected comments. This cannot be undone."},
	}
}

